/**
 * /app/styleguide — Design Token Reference
 *
 * Pulls from @/styles/design-tokens and displays every token
 * so the team can reference names, values, and visuals in one place.
 */

import { colors, typography, spacing, radii, shadows, breakpoints, layout } from '@/styles/design-tokens'

// ─── Section shell ────────────────────────────────────────────────────────────

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <section className="mb-16">
      <h2
        style={{
          fontFamily: colors.semantic.brandPrimary,
          fontSize: 22,
          fontWeight: 700,
          letterSpacing: '0.04em',
          textTransform: 'uppercase',
          borderBottom: `1px solid ${colors.semantic.border}`,
          paddingBottom: 10,
          marginBottom: 24,
          color: colors.semantic.text,
        }}
      >
        {title}
      </h2>
      {children}
    </section>
  )
}

// ─── Color swatch ────────────────────────────────────────────────────────────

function ColorSwatch({ name, value }: { name: string; value: string }) {
  const isDark = isColorDark(value)
  return (
    <div style={{ width: 140, flexShrink: 0 }}>
      <div
        style={{
          height: 64,
          borderRadius: 8,
          background: value,
          border: `1px solid ${colors.semantic.border}`,
          marginBottom: 6,
        }}
      />
      <p style={{ fontSize: 11, fontWeight: 600, color: colors.semantic.text, margin: 0, lineHeight: 1.4 }}>
        {name}
      </p>
      <p style={{ fontSize: 11, color: colors.semantic.textSecondary, margin: 0, fontFamily: 'monospace' }}>
        {value}
      </p>
    </div>
  )
}

function ColorGroup({ title, entries }: { title: string; entries: [string, string][] }) {
  return (
    <div style={{ marginBottom: 24 }}>
      <p style={{ fontSize: 13, fontWeight: 600, color: colors.semantic.textSecondary, marginBottom: 10, marginTop: 0 }}>
        {title}
      </p>
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12 }}>
        {entries.map(([name, value]) => (
          <ColorSwatch key={name} name={name} value={value} />
        ))}
      </div>
    </div>
  )
}

// ─── Typography sample ───────────────────────────────────────────────────────

function TypeRow({
  token,
  fontFamily,
  fontSize,
  lineHeight,
  fontWeight,
  textTransform,
  mobileFontSize,
}: {
  token: string
  fontFamily: string
  fontSize: number
  lineHeight: number
  fontWeight: number
  textTransform?: string
  mobileFontSize?: number
}) {
  const family =
    fontFamily === 'secondary'
      ? "'BigCaslonRegular', Georgia, serif"
      : "'Lato', system-ui, sans-serif"

  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: '160px 1fr',
        alignItems: 'center',
        gap: 16,
        padding: '10px 0',
        borderBottom: `1px solid ${colors.semantic.border}`,
      }}
    >
      <div>
        <code
          style={{
            fontSize: 11,
            background: colors.semantic.surfacePrimary,
            padding: '2px 6px',
            borderRadius: 4,
            color: colors.semantic.colorPrimary,
            fontFamily: 'monospace',
          }}
        >
          {token}
        </code>
        <p style={{ fontSize: 10, color: colors.semantic.textSecondary, margin: '4px 0 0', fontFamily: 'monospace' }}>
          {fontSize}px / {lineHeight}px · w{fontWeight}
          {mobileFontSize ? ` · mob ${mobileFontSize}px` : ''}
        </p>
      </div>
      <p
        style={{
          fontFamily: family,
          fontSize,
          lineHeight: `${lineHeight}px`,
          fontWeight,
          textTransform: textTransform as React.CSSProperties['textTransform'],
          color: colors.semantic.text,
          margin: 0,
          overflow: 'hidden',
          textOverflow: 'ellipsis',
          whiteSpace: 'nowrap',
        }}
      >
        The quick brown fox jumps over the lazy dog
      </p>
    </div>
  )
}

// ─── Spacing token ───────────────────────────────────────────────────────────

function SpacingRow({ name, value }: { name: string; value: number }) {
  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 16,
        padding: '8px 0',
        borderBottom: `1px solid ${colors.semantic.border}`,
      }}
    >
      <code style={{ width: 80, fontSize: 12, fontFamily: 'monospace', color: colors.semantic.colorPrimary, flexShrink: 0 }}>
        {name}
      </code>
      <span style={{ width: 48, fontSize: 12, color: colors.semantic.textSecondary, fontFamily: 'monospace', flexShrink: 0 }}>
        {value}px
      </span>
      <div
        style={{
          height: 20,
          width: value,
          background: colors.semantic.info,
          borderRadius: 2,
          flexShrink: 0,
        }}
      />
    </div>
  )
}

// ─── Radius token ────────────────────────────────────────────────────────────

function RadiusCard({ name, value }: { name: string; value: number }) {
  const display = value >= 9999 ? '9999' : value
  return (
    <div style={{ textAlign: 'center', width: 100 }}>
      <div
        style={{
          width: 80,
          height: 80,
          background: colors.semantic.surfaceSecondary,
          border: `2px solid ${colors.semantic.border}`,
          borderRadius: Math.min(value, 40),
          margin: '0 auto 8px',
        }}
      />
      <code style={{ fontSize: 11, fontFamily: 'monospace', color: colors.semantic.colorPrimary }}>
        {name}
      </code>
      <p style={{ fontSize: 11, color: colors.semantic.textSecondary, margin: '2px 0 0', fontFamily: 'monospace' }}>
        {display}px
      </p>
    </div>
  )
}

// ─── Shadow card ─────────────────────────────────────────────────────────────

function ShadowCard({ name, value }: { name: string; value: string }) {
  return (
    <div style={{ width: 160, textAlign: 'center' }}>
      <div
        style={{
          width: 80,
          height: 60,
          background: colors.semantic.colorSecondary,
          borderRadius: 8,
          boxShadow: value,
          margin: '0 auto 10px',
        }}
      />
      <code style={{ fontSize: 11, fontFamily: 'monospace', color: colors.semantic.colorPrimary }}>
        {name}
      </code>
    </div>
  )
}

// ─── Breakpoint row ──────────────────────────────────────────────────────────

function BreakpointRow({ name, value }: { name: string; value: string }) {
  const px = parseInt(value, 10)
  const maxPx = 1440
  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 16,
        padding: '8px 0',
        borderBottom: `1px solid ${colors.semantic.border}`,
      }}
    >
      <code style={{ width: 48, fontSize: 12, fontFamily: 'monospace', color: colors.semantic.colorPrimary, flexShrink: 0 }}>
        {name}
      </code>
      <span style={{ width: 56, fontSize: 12, color: colors.semantic.textSecondary, fontFamily: 'monospace', flexShrink: 0 }}>
        {value}
      </span>
      <div
        style={{
          flex: 1,
          height: 8,
          background: colors.semantic.surfacePrimary,
          borderRadius: 4,
          overflow: 'hidden',
        }}
      >
        <div
          style={{
            height: '100%',
            width: `${(px / maxPx) * 100}%`,
            background: colors.semantic.colorPrimary,
            borderRadius: 4,
          }}
        />
      </div>
    </div>
  )
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function isColorDark(hex: string): boolean {
  const h = hex.replace('#', '')
  const r = parseInt(h.substring(0, 2), 16)
  const g = parseInt(h.substring(2, 4), 16)
  const b = parseInt(h.substring(4, 6), 16)
  return (r * 299 + g * 587 + b * 114) / 1000 < 128
}

function objEntries<T extends Record<string, string>>(obj: T): [string, string][] {
  return Object.entries(obj) as [string, string][]
}

